input.command:
kubectl get ingress -n demo -o json | python3 -c '
import json,sys
d=json.load(sys.stdin)
for it in d["items"]:
    rules=it["spec"]["rules"]
    for r in rules:
        if r.get("host")=="rate.example.com":
            print("NAME:",it["metadata"]["name"])
            print("ANN:",json.dumps({k:v for k,v in it["metadata"].get("annotations",{}).items() if "last-applied" not in k},indent=2))
            for p in r["http"]["paths"]:
                print("  path",p["path"],p["pathType"],"->",p["backend"]["service"]["name"])
            print()
'

